using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9: HasIndex now throws for Cosmos entities — removed.
        // Cosmos indexing is managed via the container's indexing policy.

        // EF Core 9: Discriminator property renamed from "Discriminator" to "$type".
        // Preserve the old name so existing documents remain readable.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // EF Core 9: id no longer includes the discriminator (was "Blog|1", now "1").
        // Preserve the old compound format so existing documents are still found.
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

